import React, { useState, useRef, useEffect } from 'react';
import Loading from './components/Loading';
import Navbar from './components/Navbar';
import HomePage from './components/HomePage';
import InvitationCover from './components/InvitationCover';
import Countdown from './components/Countdown';
import PhotoGallery from './components/PhotoGallery';
import Footer from './components/Footer';

const playlist = [
  '/audio/marriage.mp3',
  '/audio/audio1.mp3',
  '/audio/audio2.mp3',
];

const App: React.FC = () => {
  const [loaded, setLoaded] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);
  const [playing, setPlaying] = useState(false);
  const [currentTrack, setCurrentTrack] = useState(0);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const handleEnded = () => {
      const nextTrack = (currentTrack + 1) % playlist.length;
      setCurrentTrack(nextTrack);
    };

    audio.addEventListener('ended', handleEnded);
    return () => audio.removeEventListener('ended', handleEnded);
  }, [currentTrack]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    if (playing) {
      audio.play().catch(() => {});
    } else {
      audio.pause();
    }
  }, [playing]);

  const toggleAudio = () => {
    setPlaying(!playing);
  };

  return (
    <>
      {!loaded && <Loading onComplete={() => setLoaded(true)} />}
      <div style={{
        opacity: loaded ? 1 : 0,
        transition: 'opacity 0.6s ease',
        minHeight: '100vh',
      }}>
        {/* Global Audio Player */}
        <audio 
          ref={audioRef} 
          src={playlist[currentTrack]} 
          preload="auto"
          onLoadedData={() => {
            if (playing) {
              audioRef.current?.play().catch(() => {});
            }
          }}
        />

        {/* Audio Control Button */}
        <div style={{
          position: 'fixed',
          bottom: 30,
          right: 30,
          zIndex: 999,
          backgroundColor: '#FFD700',
          borderRadius: '50%',
          width: 60,
          height: 60,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          cursor: 'pointer',
          boxShadow: '0 4px 15px rgba(255, 215, 0, 0.4)',
          border: 'none',
          fontSize: 24,
          transition: 'all 0.3s ease',
        }}
        onClick={toggleAudio}
        onMouseEnter={(e) => {
          (e.currentTarget as HTMLDivElement).style.transform = 'scale(1.15)';
          (e.currentTarget as HTMLDivElement).style.boxShadow = '0 6px 25px rgba(255, 215, 0, 0.6)';
        }}
        onMouseLeave={(e) => {
          (e.currentTarget as HTMLDivElement).style.transform = 'scale(1)';
          (e.currentTarget as HTMLDivElement).style.boxShadow = '0 4px 15px rgba(255, 215, 0, 0.4)';
        }}
        title="Toggle Music">
          {playing ? '🔊' : '🔇'}
        </div>

        <Navbar />
        <main>
          <HomePage audioPlaying={playing} onAudioToggle={toggleAudio} />
          <InvitationCover />
          <Countdown />
          <PhotoGallery />
        </main>
        <Footer />
      </div>
    </>
  );
};

export default App;
